    # Find the smallest number of colors (up to ``colors``) whose
    # quantized output has a mean square error at or below
    # ``error_threshold``. Falls back to ``colors`` if the threshold
    # can't be met.
    from . import ImageChops, ImageStat

    reference = self.convert("RGB")

    def mean_square_error(quantized_im):
        diff = ImageChops.difference(reference, quantized_im.convert("RGB"))
        stat = ImageStat.Stat(diff)
        return sum(rms**2 for rms in stat.rms) / len(stat.rms)

